def _batch_iterable(
    iterable: cabc.Iterable[t.Any], batch_size: int
) -> cabc.Iterator[tuple[t.Any, ...]]:
    """Yield successive batches of up to ``batch_size`` items from
    ``iterable``.
    """
    it = iter(iterable)

    while True:
        batch = tuple(itertools.islice(it, batch_size))

        if not batch:
            return

        yield batch


